import { useChat } from '@agentskit/react'
import type { ChatConfig } from '@agentskit/core'

export function AgentsKitChat(props: { config: ChatConfig }) {
  const chat = useChat(props.config)
  return (
    <div data-ak-chat>
      <div data-ak-messages>
        {chat.messages.map(m => (
          <div key={m.id} data-ak-message data-ak-role={m.role}>
            {m.content}
          </div>
        ))}
      </div>
      <form
        data-ak-form
        onSubmit={e => {
          e.preventDefault()
          chat.send(chat.input)
        }}
      >
        <input
          data-ak-input
          value={chat.input}
          onChange={e => chat.setInput(e.currentTarget.value)}
          placeholder='Type a message...'
        />
        <button data-ak-submit type='submit' disabled={chat.status === 'streaming'}>
          Send
        </button>
      </form>
    </div>
  )
}
